import{_ as t,o as r,c as o,a3 as n}from"./chunks/framework.CjquFG0V.js";const m=JSON.parse('{"title":"15. Flexible Working Arrangements","description":"","frontmatter":{"title":"15. Flexible Working Arrangements","eba":"Doctors in Training 2022-2026","topics":["employment","flexible-work","preliminary"]},"headers":[],"relativePath":"ebas/doctors-in-training/consultation-disputes/15-flexible-working-arrangements.md","filePath":"ebas/doctors-in-training/consultation-disputes/15-flexible-working-arrangements.md"}'),s={name:"ebas/doctors-in-training/consultation-disputes/15-flexible-working-arrangements.md"};function a(i,e,l,g,c,p){return r(),o("div",null,[...e[0]||(e[0]=[n('<h1 id="_15-flexible-working-arrangements" tabindex="-1">15. Flexible Working Arrangements <a class="header-anchor" href="#_15-flexible-working-arrangements" aria-label="Permalink to &quot;15. Flexible Working Arrangements&quot;">​</a></h1><p><strong>15.1</strong> The Act entitles specified Doctors to request flexible working arrangements in specified circumstances.</p><p><strong>15.2</strong> The specified Doctors are:</p><p><strong>(a)</strong> full time or part time Doctors with at least 12 months’ continuous service (calculated in accordance with subclauses 68.3 to 68.5); and</p><p><strong>(b)</strong> long term casual Doctor with a reasonable expectation of continuing employment by the Health Service on a regular and systematic basis.</p><p><strong>15.3</strong> The specified circumstances are if the Doctor:</p><p><strong>(a)</strong> is the parent, or has responsibility for the care, of a child who is of school age or younger;</p><p><strong>(b)</strong> is a carer within the meaning of the Carer Recognition Act 2010 (Vic) (for example, caring for someone who has a disability, a medical condition (including a terminal or chronic illness), a mental illness or is frail or aged);</p><p><strong>(c)</strong> has a disability;</p><p><strong>(d)</strong> is aged 55 years or older;</p><p><strong>(e)</strong> is experiencing violence from a member of the Doctor’s family; or</p><p><strong>(f)</strong> provides care or support to a member of the Doctor’s immediate family, or a member of the Doctor’s household, who requires care or support because the member is experiencing violence or abuse from the member’s family.</p><p><strong>15.4</strong> A request for flexible working arrangements includes (but is not limited to) a request to work part-time upon return to work after the birth or adoption of a child to assist the Doctor to care for the child.</p><p><strong>15.5</strong> Changes in working arrangements may include, but are not limited to, hours of work, patterns of work and location of work.</p><p><strong>15.6</strong> The request must be in writing, set out details of the change sought and the reasons for the change.</p><p><strong>15.7</strong> The Health Service must give the Doctor a written response to the request within 21 days, stating whether the Health Service grants or refuses the request. A request may only be refused on reasonable business grounds as described in the NES.</p><p><strong>15.8</strong> Where the Health Service refuses the request, the written response must include details of the reasons for the refusal.</p><p><strong>15.9</strong> Where a request for flexible work arrangements is made, a Doctor or Health Service is entitled to meet with the other party to discuss:</p><p><strong>(a)</strong> the request;</p><p><strong>(b)</strong> an alternative to the request; or</p><p><strong>(c)</strong> reasons for a refusal on reasonable business grounds.</p><p><strong>15.10</strong> A Doctor or Health Service may choose to be represented at a meeting under subclause 15.9 by a representative including the Association or employer organisation.</p><p><strong>15.11</strong> The dispute resolution procedure in this Agreement will apply to any dispute / grievance arising in relation to a request for flexible working arrangements.</p><p><strong>15.12</strong> Other entitlements relevant to family violence can be found at <a href="/eba/ebas/doctors-in-training/leave/71-family-violence-leave.html">clause 71</a> (Family Violence Leave).</p><p>Plain language terms: flex work, flexible hours, WFH.</p>',25)])])}const u=t(s,[["render",a]]);export{m as __pageData,u as default};
